// Chess Rook (Castle) — hollow, turned-ivory look.
// Body via CrossSection.ofPolygons + Manifold.revolve; crenellations + hollow
// interior via boolean subtraction. revolve() spins the 2D profile around the
// Y axis and remaps to Z-up: profile X = radial distance, profile Y = height.
const { Manifold, CrossSection, label } = api;

const segments = 48; // smooth circular geometry

// ---------------------------------------------------------------
// 1. BODY — outer silhouette profile (CCW), refined for an elegant rook:
//    flared foot -> waisted shaft -> cavetto collar -> straight parapet wall.
// ---------------------------------------------------------------
const profile = [
  [0, 0.0], // center bottom
  [6.4, 0.0], // foot outer edge (flat bottom)
  [6.4, 1.0], // foot lip
  [5.4, 1.9], // foot rounds inward
  [4.4, 3.0], // base-to-shaft transition
  [3.7, 4.5], // lower shaft (waist begins)
  [3.45, 7.0], // narrowest waist
  [3.4, 10.0], // upper shaft
  [3.5, 12.2], // shaft swells slightly toward collar
  [3.7, 13.0], // collar begins
  [4.9, 13.7], // collar (cavetto) flares out
  [5.0, 14.2], // collar top / parapet base
  [5.0, 16.6], // top of parapet wall
  [0, 16.6], // close across to center axis
];

const body = Manifold.revolve(CrossSection.ofPolygons([profile]), segments);

// ---------------------------------------------------------------
// 2. HOLLOW INTERIOR — subtract a revolved inner profile; keep a solid floor.
// ---------------------------------------------------------------
const interiorProfile = [
  [0, 1.6], // floor at Z=1.6 (solid foot below)
  [2.9, 1.6], // inner wall at base
  [2.7, 7.0], // tapers in through waist
  [2.55, 12.0], // narrowest inner wall
  [2.8, 13.2], // widens into collar
  [3.4, 14.2], // inner wall of parapet
  [3.4, 17.2], // extends above top to open the bore
  [0, 17.2], // center top
];

const interior = Manifold.revolve(CrossSection.ofPolygons([interiorProfile]), segments);
const hollowBody = body.subtract(interior);

// ---------------------------------------------------------------
// 3. CRENELLATIONS — 5 evenly spaced crenels (gaps) alternating with 5 merlons.
//    Each crenel and each merlon spans 36°. Cuts start at Z=15.0 so a solid
//    parapet ring (Z 14.2->15.0) remains beneath the merlons, keeping the
//    piece one connected solid with cleanly even battlements.
// ---------------------------------------------------------------
const numCrenels = 5;
const gapDeg = 360 / (numCrenels * 2); // 36° per crenel
const gapRad = (gapDeg * Math.PI) / 180;

const cutBottomZ = 15.0; // ring band remains 14.2->15.0
const cutH = (16.6 - cutBottomZ) + 0.2; // through the top, with overlap
const parapetOuterR = 5.0;
const radialInner = 2.8; // inside the inner wall
const radialOuter = 6.5; // beyond the outer wall
const radialDepth = radialOuter - radialInner;
const arcWidth = 2 * parapetOuterR * Math.sin(gapRad / 2); // chord of the 36° gap

const crenelCuts = [];
for (let i = 0; i < numCrenels; i++) {
  const angle = (i * 360) / numCrenels;
  const block = Manifold.cube([radialDepth, arcWidth, cutH])
    .translate([radialInner, -arcWidth / 2, cutBottomZ - 0.1])
    .rotate([0, 0, angle]);
  crenelCuts.push(block);
}

const rook = hollowBody.subtract(Manifold.union(crenelCuts));

// Single label so the whole piece can be painted ivory in one op.
return label(rook, 'rook');
